import React, { useState } from 'react';
import { Link, Outlet, useLocation } from 'react-router-dom';
import { Menu, X, Mail, Monitor, Github, Linkedin } from 'lucide-react';
import { PERSONAL_INFO } from '../constants';

const Layout: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const location = useLocation();

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Projects', path: '/projects' },
    { name: 'About', path: '/about' },
  ];

  const isActive = (path: string) => {
    if (path === '/' && location.pathname !== '/') return false;
    return location.pathname.startsWith(path);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-800 bg-white">
      {/* Navigation */}
      <nav className="sticky top-0 z-50 bg-white/95 backdrop-blur-sm transition-all duration-300">
        <div className="max-w-7xl mx-auto px-6 lg:px-8">
          <div className="flex justify-between items-center h-24">
            <div className="flex items-center">
              <Link to="/" className="text-2xl font-bold text-primary">
                AJWAH.
              </Link>
            </div>

            {/* Desktop Menu */}
            <div className="hidden md:flex items-center space-x-8">
              {navLinks.map((link) => (
                <Link
                  key={link.name}
                  to={link.path}
                  className={`text-lg transition-colors duration-200 ${
                    isActive(link.path)
                      ? 'text-primary'
                      : 'text-slate-600 hover:text-primary'
                  }`}
                >
                  {link.name}
                </Link>
              ))}
              <Link
                to="/contact"
                className="inline-flex items-center px-6 py-2.5 border-2 border-primary text-primary hover:bg-primary hover:text-white rounded-full text-base font-medium transition-all duration-300"
              >
                Say Hello
              </Link>
            </div>

            {/* Mobile menu button */}
            <div className="flex items-center md:hidden">
              <button
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className="inline-flex items-center justify-center p-2 rounded-md text-slate-600 hover:text-primary focus:outline-none"
              >
                {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMenuOpen && (
          <div className="md:hidden bg-white border-b border-slate-100 absolute w-full shadow-lg">
            <div className="px-4 pt-2 pb-6 space-y-2">
              {navLinks.map((link) => (
                <Link
                  key={link.name}
                  to={link.path}
                  onClick={() => setIsMenuOpen(false)}
                  className={`block px-3 py-3 rounded-md text-base font-medium ${
                    isActive(link.path)
                      ? 'text-primary bg-indigo-50'
                      : 'text-slate-600 hover:text-primary'
                  }`}
                >
                  {link.name}
                </Link>
              ))}
              <Link
                to="/contact"
                onClick={() => setIsMenuOpen(false)}
                className="block mt-4 text-center w-full px-6 py-3 border-2 border-primary text-primary font-medium rounded-full"
              >
                Say Hello
              </Link>
            </div>
          </div>
        )}
      </nav>

      {/* Main Content */}
      <main className="flex-grow">
        <Outlet />
      </main>

      {/* Footer */}
      <footer className="bg-primary text-white pt-16 pb-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">

          <Link to="/" className="text-3xl font-bold text-white/90 inline-block mb-8">
            AJWAH.
          </Link>

          <p className="text-indigo-200 text-xl max-w-lg mx-auto mb-10 leading-relaxed">
            Living, learning, and leveling up one day at a time.
          </p>

          <div className="flex justify-center space-x-6 mb-12">
            <a href={`mailto:${PERSONAL_INFO.email}`} className="p-3 border-2 border-indigo-300/30 rounded-full hover:bg-white hover:text-primary hover:border-white transition-all duration-300">
              <Mail size={20} />
            </a>
            <a href={PERSONAL_INFO.social.linkedin} target="_blank" rel="noopener noreferrer" className="p-3 border-2 border-indigo-300/30 rounded-full hover:bg-white hover:text-primary hover:border-white transition-all duration-300">
              <Linkedin size={20} />
            </a>
            <a href={PERSONAL_INFO.social.github} target="_blank" rel="noopener noreferrer" className="p-3 border-2 border-indigo-300/30 rounded-full hover:bg-white hover:text-primary hover:border-white transition-all duration-300">
              <Github size={20} />
            </a>
            <a href={PERSONAL_INFO.social.portfolio} target="_blank" rel="noopener noreferrer" className="p-3 border-2 border-indigo-300/30 rounded-full hover:bg-white hover:text-primary hover:border-white transition-all duration-300">
              <Monitor size={20} />
            </a>
          </div>

          <div className="text-indigo-300 text-sm">
             Handcrafted by me &copy; {new Date().getFullYear()}
          </div>
        </div>
      </footer>
    </div>
  );
};

export default Layout;

import React from 'react';
import { useParams, Link } from 'react-router-dom';
import { PROJECTS } from '../constants';
import { ArrowLeft, ExternalLink, CheckCircle, Code, Server, Layers, Instagram, Image as ImageIcon } from 'lucide-react';

const ProjectDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const project = PROJECTS.find(p => p.id === id);

  if (!project) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <h2 className="text-2xl font-bold text-slate-900 mb-4">Project Not Found</h2>
        <Link to="/projects" className="text-primary hover:underline flex items-center">
          <ArrowLeft size={16} className="mr-2" /> Back to Projects
        </Link>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen pb-20">
      {/* Hero Section */}
      <div className="bg-slate-900 pt-32 pb-32 text-white relative overflow-hidden">
        {/* Abstract shapes/bg */}
        <div className="absolute top-0 right-0 w-1/2 h-full bg-primary/10 rounded-l-full blur-3xl transform translate-x-1/4"></div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <Link to="/projects" className="inline-flex items-center text-slate-400 hover:text-white mb-8 transition-colors">
            <ArrowLeft size={20} className="mr-2" /> Back to Projects
          </Link>

          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
            <div className="max-w-3xl">
              <div className="inline-block px-4 py-1.5 rounded-full bg-primary/20 text-primary border border-primary/30 text-sm font-bold mb-6 tracking-wide uppercase">
                {project.category}
              </div>
              <h1 className="text-4xl md:text-5xl lg:text-6xl font-extrabold mb-6 leading-tight">
                {project.title}
              </h1>
              <p className="text-xl text-slate-300 leading-relaxed max-w-2xl">
                {project.description}
              </p>
            </div>

            <div className="flex flex-col gap-4">
              {project.liveLink && (
                <a 
                  href={project.liveLink}
                  target="_blank"
                  rel="noopener noreferrer" 
                  className="inline-flex items-center justify-center px-8 py-3 bg-primary hover:bg-indigo-600 text-white font-bold rounded-full transition-all duration-300 shadow-lg hover:shadow-primary/50"
                >
                  Visit Live Site <ExternalLink size={20} className="ml-2" />
                </a>
              )}
              {project.instagramLink && (
                <a 
                  href={project.instagramLink}
                  target="_blank"
                  rel="noopener noreferrer" 
                  className="inline-flex items-center justify-center px-8 py-3 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-full transition-all duration-300 shadow-lg"
                >
                  View on Instagram <Instagram size={20} className="ml-2" />
                </a>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Main Image - Full Width of Screen */}
      <div className="w-full bg-slate-100 relative group overflow-hidden border-b border-slate-200">
         <img 
           src={project.imageUrl} 
           alt={project.title} 
           className="w-full h-auto min-h-[400px] max-h-[800px] object-cover object-top"
         />
      </div>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 relative z-20">

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            {/* Sidebar / Info */}
            <div className="order-2 lg:order-1">
              <div className="bg-slate-50 rounded-2xl p-8 border border-slate-100 sticky top-28">
                <div className="space-y-8">
                  <div>
                    <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Role</h3>
                    <p className="text-lg font-semibold text-slate-900">{project.role || "Lead Developer"}</p>
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Client</h3>
                    <p className="text-lg font-semibold text-slate-900">{project.client || "Confidential"}</p>
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Year</h3>
                    <p className="text-lg font-semibold text-slate-900">{project.year || "2024"}</p>
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">Tools & Tech</h3>
                    <div className="flex flex-wrap gap-2">
                      {project.techStack.map(tech => (
                        <span key={tech} className="px-3 py-1.5 bg-white border border-slate-200 text-slate-700 text-xs font-semibold rounded-md shadow-sm">
                          {tech}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Case Study Details */}
            <div className="lg:col-span-2 space-y-12 order-1 lg:order-2">

              {/* Overview */}
              <div>
                <h2 className="text-3xl font-bold text-slate-900 mb-6 flex items-center">
                  <Layers className="text-primary mr-3" /> Project Overview
                </h2>
                <p className="text-lg text-slate-600 leading-relaxed">
                  {project.fullDescription || project.description}
                </p>
              </div>

              {/* Problem */}
              {project.problem && (
                <div className="bg-red-50 p-8 rounded-2xl border border-red-100">
                  <h2 className="text-2xl font-bold text-red-900 mb-4">The Challenge</h2>
                  <p className="text-lg text-red-800/80 leading-relaxed">
                    {project.problem}
                  </p>
                </div>
              )}

              {/* Solution */}
              {project.solution && (
                <div className="bg-green-50 p-8 rounded-2xl border border-green-100">
                  <h2 className="text-2xl font-bold text-green-900 mb-4">The Solution</h2>
                  <p className="text-lg text-green-800/80 leading-relaxed">
                    {project.solution}
                  </p>
                </div>
              )}

              {/* Features */}
              {project.features && (
                <div>
                   <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center">
                    <Code className="text-primary mr-3" /> Key Features
                  </h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {project.features.map((feature, idx) => (
                      <div key={idx} className="flex items-start p-4 bg-slate-50 rounded-xl border border-slate-100">
                        <CheckCircle className="text-primary w-5 h-5 mr-3 mt-0.5 flex-shrink-0" />
                        <span className="text-slate-700 font-medium">{feature}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Results */}
              {project.results && (
                <div>
                   <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center">
                    <Server className="text-primary mr-3" /> Impact & Results
                  </h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {project.results.map((result, idx) => (
                      <div key={idx} className="p-6 bg-slate-900 rounded-xl text-white shadow-lg">
                        <p className="font-bold text-lg leading-snug">{result}</p>
                      </div>
                    ))}
                  </div>
                </div>
              )}

            </div>
          </div>


        {/* Gallery Section */}
        {project.gallery && project.gallery.length > 0 && (
          <div className="mt-20">
            <h2 className="text-3xl font-bold text-slate-900 mb-10 text-center flex items-center justify-center">
              <ImageIcon className="mr-3" /> Project Gallery
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {project.gallery.map((img, idx) => (
                <div key={idx} className="rounded-2xl overflow-hidden shadow-lg border border-slate-100 bg-slate-50 group hover:shadow-2xl transition-shadow duration-300">
                  <img 
                    src={img} 
                    alt={`${project.title} screenshot ${idx + 1}`} 
                    className="w-full h-auto object-cover transform group-hover:scale-[1.02] transition-transform duration-500"
                    loading="lazy"
                  />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Next Project CTA */}
        <div className="mt-20 text-center">
          <p className="text-slate-500 mb-4">Ready to start your own project?</p>
          <Link to="/contact" className="inline-flex items-center justify-center px-8 py-3 bg-white text-primary border-2 border-primary font-bold rounded-full hover:bg-primary hover:text-white transition-all duration-300">
            Let's Talk
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ProjectDetail;

