import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { PROJECTS } from '../constants';
import { ArrowLeft, ExternalLink, CheckCircle, Code, Server, Layers, Instagram, ChevronLeft, ChevronRight } from 'lucide-react';

const ProjectDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  const project = PROJECTS.find(p => p.id === id);

  if (!project) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <h2 className="text-2xl font-bold text-slate-900 mb-4">Project Not Found</h2>
        <Link to="/projects" className="text-primary hover:underline flex items-center">
          <ArrowLeft size={16} className="mr-2" /> Back to Projects
        </Link>
      </div>
    );
  }

  // Combine main image and gallery into one array for the carousel
  const allImages = [project.imageUrl, ...(project.gallery || [])];

  const nextImage = () => {
    setCurrentImageIndex((prev) => (prev + 1) % allImages.length);
  };

  const prevImage = () => {
    setCurrentImageIndex((prev) => (prev - 1 + allImages.length) % allImages.length);
  };

  const goToImage = (index: number) => {
    setCurrentImageIndex(index);
  };

  return (
    <div className="bg-white min-h-screen pb-20">
      {/* Hero Section */}
      <div className="bg-slate-900 pt-32 pb-48 text-white relative overflow-hidden">
        {/* Abstract shapes/bg */}
        <div className="absolute top-0 right-0 w-1/2 h-full bg-primary/10 rounded-l-full blur-3xl transform translate-x-1/4"></div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <Link to="/projects" className="inline-flex items-center text-slate-400 hover:text-white mb-8 transition-colors">
            <ArrowLeft size={20} className="mr-2" /> Back to Projects
          </Link>

          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
            <div className="max-w-3xl">
              <div className="inline-block px-4 py-1.5 rounded-full bg-primary/20 text-primary border border-primary/30 text-sm font-bold mb-6 tracking-wide uppercase">
                {project.category}
              </div>
              <h1 className="text-4xl md:text-5xl lg:text-6xl font-extrabold mb-6 leading-tight">
                {project.title}
              </h1>
              <p className="text-xl text-slate-300 leading-relaxed max-w-2xl">
                {project.description}
              </p>
            </div>

            <div className="flex flex-col gap-4">
              {project.liveLink && (
                <a 
                  href={project.liveLink}
                  target="_blank"
                  rel="noopener noreferrer" 
                  className="inline-flex items-center justify-center px-8 py-3 bg-primary hover:bg-indigo-600 text-white font-bold rounded-full transition-all duration-300 shadow-lg hover:shadow-primary/50"
                >
                  Visit Live Site <ExternalLink size={20} className="ml-2" />
                </a>
              )}
              {project.instagramLink && (
                <a 
                  href={project.instagramLink}
                  target="_blank"
                  rel="noopener noreferrer" 
                  className="inline-flex items-center justify-center px-8 py-3 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-full transition-all duration-300 shadow-lg"
                >
                  View on Instagram <Instagram size={20} className="ml-2" />
                </a>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Carousel Section (Top of Content) */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-32 relative z-20 mb-20">
        <div className="relative bg-slate-50 rounded-2xl overflow-hidden shadow-2xl border border-slate-200">

          {/* Main Display Area */}
          <div className="relative aspect-video md:aspect-[16/9] lg:aspect-[2/1] max-h-[700px] w-full bg-slate-100 flex items-center justify-center">
             <img 
               src={allImages[currentImageIndex]} 
               alt={`Project slide ${currentImageIndex + 1}`}
               className="w-full h-full object-contain object-center"
             />

             {/* Navigation Arrows */}
             <div className="absolute inset-0 flex items-center justify-between p-4 pointer-events-none">
               <button 
                 onClick={prevImage}
                 className="pointer-events-auto p-2 rounded-full bg-white/80 hover:bg-white text-slate-800 shadow-lg backdrop-blur-sm transition-all transform hover:scale-110"
                 aria-label="Previous image"
               >
                 <ChevronLeft size={28} />
               </button>
               <button 
                 onClick={nextImage}
                 className="pointer-events-auto p-2 rounded-full bg-white/80 hover:bg-white text-slate-800 shadow-lg backdrop-blur-sm transition-all transform hover:scale-110"
                 aria-label="Next image"
               >
                 <ChevronRight size={28} />
               </button>
             </div>

             {/* Slide Counter/Badge */}
             <div className="absolute bottom-4 right-4 bg-black/60 text-white px-3 py-1 rounded-full text-xs font-bold backdrop-blur-md">
                {currentImageIndex + 1} / {allImages.length}
             </div>
          </div>

          {/* Thumbnails Strip */}
          <div className="bg-white p-4 border-t border-slate-200 overflow-x-auto">
            <div className="flex space-x-3 justify-center min-w-max">
              {allImages.map((img, idx) => (
                <button
                  key={idx}
