// Tilt Card Component
const ProjectCard: React.FC<{ project: any }> = ({ project }) => {
  const cardRef = useRef<HTMLDivElement>(null);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const card = cardRef.current;
    if (!card) return;

    const rect = card.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const centerX = rect.width / 2;
    const centerY = rect.height / 2;

    // Calculate rotation (limit to 10 degrees)
    const rotateX = ((y - centerY) / centerY) * -5;
    const rotateY = ((x - centerX) / centerX) * 5;

    card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale(1.02)`;
  };

  const handleMouseLeave = () => {
    const card = cardRef.current;
    if (!card) return;
    card.style.transform = `perspective(1000px) rotateX(0deg) rotateY(0deg) scale(1)`;
  };

  return (
    <div 
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="tilt-card bg-white rounded-3xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 flex flex-col group border border-slate-100 h-full relative"
    >
       <div className="h-72 overflow-hidden relative">
        <img 
          src={project.imageUrl} 
          alt={project.title} 
          className="w-full h-full object-cover object-top transition-transform duration-700 pointer-events-none group-hover:scale-105"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent opacity-60 group-hover:opacity-40 transition-opacity duration-300"></div>
        <div className="absolute top-4 right-4 bg-white/95 backdrop-blur-md px-4 py-1.5 rounded-full text-xs font-bold text-primary shadow-sm uppercase tracking-wider transform translate-y-[-150%] group-hover:translate-y-0 transition-transform duration-300 z-10">
            {project.category}
        </div>
      </div>

      <div className="p-8 flex flex-col flex-grow text-left relative z-10 bg-white">
        <h3 className="text-2xl font-bold text-slate-900 mb-3 group-hover:text-primary transition-colors">{project.title}</h3>
        <p className="text-slate-600 mb-6 line-clamp-3 flex-grow leading-relaxed">{project.description}</p>

        <div className="mt-auto pt-6 border-t border-slate-100">
          <Link 
            to={`/projects/${project.id}`} 
            className="inline-flex items-center font-bold text-primary hover:text-indigo-800 transition-colors group/link"
          >
            View Case Study <ArrowRight size={18} className="ml-2 group-hover/link:translate-x-1 transition-transform" />
          </Link>
        </div>
      </div>
    </div>
  );
};

