import React from 'react';
import { HashRouter, Routes, Route, useLocation } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';
import Layout from './components/Layout';
import Home from './pages/Home';
import About from './pages/About';
import Contact from './pages/Contact';
import Services from './pages/Services';
import ServiceDetail from './pages/ServiceDetail';
import Projects from './pages/Projects';
import ProjectDetail from './pages/ProjectDetail';
import SkillsVault from './pages/SkillsVault';

const PageTransition: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <motion.div
    initial={{ opacity: 0, scale: 0.98 }}
    animate={{ opacity: 1, scale: 1 }}
    exit={{ opacity: 0, scale: 1.02 }}
    transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
  >
    {children}
  </motion.div>
);

const AnimatedRoutes = () => {
  const location = useLocation();

  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        <Route path="/" element={<Layout />}>
          <Route index element={<PageTransition><Home /></PageTransition>} />
          <Route path="portfolio" element={<PageTransition><Projects /></PageTransition>} />
          <Route path="portfolio/:id" element={<PageTransition><ProjectDetail /></PageTransition>} />
          <Route path="skills-vault" element={<PageTransition><SkillsVault /></PageTransition>} />
          <Route path="my-services" element={<PageTransition><Services /></PageTransition>} />
          <Route path="my-services/:id" element={<PageTransition><ServiceDetail /></PageTransition>} />
          <Route path="about-me" element={<PageTransition><About /></PageTransition>} />
          <Route path="get-in-touch" element={<PageTransition><Contact /></PageTransition>} />

          <Route path="about" element={<PageTransition><About /></PageTransition>} />
          <Route path="contact" element={<PageTransition><Contact /></PageTransition>} />
          <Route path="projects" element={<PageTransition><Projects /></PageTransition>} />
        </Route>
      </Routes>
    </AnimatePresence>
  );
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <AnimatedRoutes />
    </HashRouter>
  );
};

export default App;

