            <a href={PERSONAL_INFO.social.github} target="_blank" rel="noopener noreferrer" className="p-4 border-2 border-slate-700 rounded-full hover:bg-primary hover:text-white hover:border-primary transition-all duration-300">
              <Github size={22} />
            </a>
          </div>

          <div className="text-slate-500 text-sm font-medium pt-8 border-t border-slate-800">
             Handcrafted by Ajwah Malik &copy; {new Date().getFullYear()} — Made with Passion.
          </div>
        </div>
      </footer>
    </div>
  );
};

export default Layout;
